/**
 * Type declaration for the Emscripten-generated PVAC WASM module.
 * The actual implementation is in pvac_wasm.mjs (generated by build-wasm.sh).
 */

interface PvacEmscriptenModule {
  ccall(name: string, returnType: string | null, argTypes: string[], args: unknown[]): unknown
  getValue(ptr: number, type: string): number
  HEAPU8: Uint8Array
  _malloc(size: number): number
  _free(ptr: number): void
}

declare const PvacModule: (opts?: object) => Promise<PvacEmscriptenModule>
export default PvacModule
